// Component Adapters

// --- HTTP handler implementation ---

static void write_body(wasi::http::types::OutgoingBody &body, std::string_view data) {
  auto stream_result = body.Write();
  if (!stream_result.has_value()) return;
  auto stream = std::move(stream_result.value());
  auto bytes = std::span<uint8_t const>(
    reinterpret_cast<uint8_t const *>(data.data()), data.size());
  stream.BlockingWriteAndFlush(bytes);
}

static void respond_simple(wasi::http::types::ResponseOutparam &&response_out,
                           uint16_t status, std::string_view body_str) {
  auto headers = wasi::http::types::Fields();
  auto response = wasi::http::types::OutgoingResponse(std::move(headers));
  response.SetStatusCode(status);
  auto body_result = response.Body();
  if (!body_result.has_value()) return;
  auto body = std::move(body_result.value());
  write_body(body, body_str);
  wasi::http::types::OutgoingBody::Finish(std::move(body), std::nullopt);
  wasi::http::types::ResponseOutparam::Set(
    std::move(response_out),
    std::expected<wasi::http::types::OutgoingResponse, wasi::http::types::ErrorCode>(std::move(response)));
}

static void handle_home(wasi::http::types::IncomingRequest &&request,
                        wasi::http::types::ResponseOutparam &&response_out) {
  respond_simple(std::move(response_out), 200, "Hello, C++ wasi:http world!\n");
}

static void handle_echo(wasi::http::types::IncomingRequest &&request,
                        wasi::http::types::ResponseOutparam &&response_out) {
  auto headers = wasi::http::types::Fields();
  auto response = wasi::http::types::OutgoingResponse(std::move(headers));
  response.SetStatusCode(200);
  auto body_result = response.Body();
  if (!body_result.has_value()) return;
  auto body = std::move(body_result.value());
  auto out_stream_result = body.Write();

  auto consume_result = request.Consume();
  if (consume_result.has_value() && out_stream_result.has_value()) {
    auto incoming_body = std::move(consume_result.value());
    auto in_stream_result = incoming_body.Stream();
    if (in_stream_result.has_value()) {
      auto in_stream = std::move(in_stream_result.value());
      auto out_stream = std::move(out_stream_result.value());
      while (true) {
        auto read_result = in_stream.BlockingRead(4096);
        if (!read_result.has_value()) break;
        auto data = std::move(*read_result);
        if (data.size() == 0) break;
        out_stream.BlockingWriteAndFlush(
          std::span<uint8_t const>(data.data(), data.size()));
      }
    }
  }

  wasi::http::types::OutgoingBody::Finish(std::move(body), std::nullopt);
  wasi::http::types::ResponseOutparam::Set(
    std::move(response_out),
    std::expected<wasi::http::types::OutgoingResponse, wasi::http::types::ErrorCode>(std::move(response)));
}

static void handle_echo_headers(wasi::http::types::IncomingRequest &&request,
                                wasi::http::types::ResponseOutparam &&response_out) {
  auto req_headers = request.Headers();
  auto entries = req_headers.Entries();

  auto resp_headers = wasi::http::types::Fields();
  for (size_t i = 0; i < entries.size(); ++i) {
    auto &[name, value] = entries[i];
    resp_headers.Append(
      std::string_view(name.data(), name.size()),
      std::span<uint8_t const>(value.data(), value.size()));
  }

  auto response = wasi::http::types::OutgoingResponse(std::move(resp_headers));
  response.SetStatusCode(200);
  auto body_result = response.Body();
  if (body_result.has_value()) {
    auto body = std::move(body_result.value());
    wasi::http::types::OutgoingBody::Finish(std::move(body), std::nullopt);
  }
  wasi::http::types::ResponseOutparam::Set(
    std::move(response_out),
    std::expected<wasi::http::types::OutgoingResponse, wasi::http::types::ErrorCode>(std::move(response)));
}

static void handle_not_found(wasi::http::types::IncomingRequest &&request,
                             wasi::http::types::ResponseOutparam &&response_out) {
  respond_simple(std::move(response_out), 404, "Not Found\n");
}

void exports::wasi::http::incoming_handler::Handle(
    ::wasi::http::types::IncomingRequest &&request,
    ::wasi::http::types::ResponseOutparam &&response_out) {
  auto path_opt = request.PathWithQuery();
  std::string_view path = path_opt.has_value()
    ? std::string_view(path_opt->data(), path_opt->size())
    : std::string_view("/");

  if (path == "/") {
    handle_home(std::move(request), std::move(response_out));
  } else if (path == "/echo") {
    handle_echo(std::move(request), std::move(response_out));
  } else if (path == "/echo-headers") {
    handle_echo_headers(std::move(request), std::move(response_out));
  } else {
    handle_not_found(std::move(request), std::move(response_out));
  }
}
